on_write:
let res = #{ action: "Allow" };
if !payload.contains("parent_id") {
    res.action = "Reject";
    res.reason = "Hierarchical nodes must specify a parent_id (or root)";
}
res

on_read:
let res = #{ payload: payload };
if payload.parent_id == query_key {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
